import React, { useState, useEffect, useRef } from 'react';
import { useDashboardLogic } from '../../hooks/useDashboardLogic';
import type { VisibilityState } from '../../types';
import { DashboardContext } from '../../contexts/DashboardContext';

import Header from '../layout/Header';
import Footer from '../layout/Footer';
import LandingPageView from './LandingPageView';
import StatusDisplay from '../upload/StatusDisplay';
import FilterSection from '../filters/FilterSection';
import KpiCards from '../kpis/KpiCards';
import TrendChart from '../charts/TrendChart';
import IndustryGrid from '../charts/IndustryGrid';
import EmployeeAnalysis from '../employees/EmployeeAnalysis';
import SummaryTable from '../tables/SummaryTable';
import WarehouseSummary from '../summary/WarehouseSummary';
import PerformanceModal from '../modals/PerformanceModal';
import UnshippedOrdersModal from '../modals/UnshippedOrdersModal';
import ProcessingLoader from '../common/ProcessingLoader';
import ExportLoader from '../common/ExportLoader';
import ChatFab from '../ai/ChatFab';
import ChatModal from '../ai/ChatModal';
import { Icon } from '../common/Icon';
import { KpiCardsSkeleton, ChartSkeleton, TableSkeleton, TabbedTableSkeleton } from '../common/SkeletonLoader';

const defaultVisibilityState: VisibilityState = {
    trendChart: true,
    industryGrid: true,
    employeeAnalysis: true,
    summaryTable: true,
};

export default function DashboardView() {
    const logic = useDashboardLogic();
    const {
        status, appState, isProcessing, isExporting, fileInfo,
        processedData, uniqueFilterOptions,
        activeModal, setActiveModal, modalData,
        isChatOpen, setIsChatOpen, chatHistory, isAiResponding,
        handleFileProcessing, handleSendMessage, openUnshippedModal, handleExport,
        filterState, processingTime, handleClearDepartments, handleClearData,
        isClearingDepartments, departmentMap
    } = logic;

    const [visibleComponents, setVisibleComponents] = useState<VisibilityState>(() => {
        try {
            const saved = localStorage.getItem('dashboard_visibleComponents');
            return saved ? JSON.parse(saved) : defaultVisibilityState;
        } catch (e) {
            return defaultVisibilityState;
        }
    });

    const [isFilterSidebarOpen, setIsFilterSidebarOpen] = useState(false);
    const dashboardContainerRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const shiftFileInputRef = useRef<HTMLInputElement>(null);

    const handleVisibilityChange = (component: keyof VisibilityState, isVisible: boolean) => {
        setVisibleComponents(prev => {
            const newState = { ...prev, [component]: isVisible };
            localStorage.setItem('dashboard_visibleComponents', JSON.stringify(newState));
            return newState;
        });
    };

    useEffect(() => {
        if (typeof lucide !== 'undefined') {
            setTimeout(() => { lucide.createIcons(); }, 100);
        }
    }, [appState, processedData, activeModal, isChatOpen]);

    const showDashboard = appState === 'dashboard' && processedData;
    const showLanding = appState === 'upload';

    const handleHeaderNewFile = () => fileInputRef.current?.click();
    const handleHeaderLoadShift = () => shiftFileInputRef.current?.click();

    return (
        <DashboardContext.Provider value={logic as any}>
            <div className="relative min-h-screen bg-slate-50 dark:bg-slate-950 grid-pattern">
                {/* Hidden File Inputs for Header Actions */}
                <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept=".xlsx, .xls" 
                    onChange={(e) => e.target.files?.[0] && handleFileProcessing(e.target.files[0])} 
                />
                <input 
                    type="file" 
                    ref={shiftFileInputRef} 
                    className="hidden" 
                    accept=".xlsx, .xls" 
                    multiple
                    onChange={(e) => e.target.files && logic.handleShiftFileProcessing(Array.from(e.target.files))} 
                />

                {/* Background Decorative Blobs */}
                <div className="fixed inset-0 overflow-hidden pointer-events-none z-0">
                    <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] bg-indigo-500/10 rounded-full blur-[120px] animate-pulse"></div>
                    <div className="absolute bottom-[-10%] left-[-10%] w-[600px] h-[600px] bg-purple-500/10 rounded-full blur-[120px]"></div>
                </div>

                <div className="relative z-10 w-full max-w-[1600px] mx-auto p-4 md:p-8">
                    {showLanding && (
                        <LandingPageView 
                            onProcessFile={handleFileProcessing} 
                            configUrl={logic.configUrl} 
                            onConfigUrlChange={logic.setConfigUrl}
                            isDeduplicationEnabled={logic.isDeduplicationEnabled}
                            onDeduplicationChange={logic.handleDeduplicationChange}
                        />
                    )}

                    {showDashboard && (
                        <div className="animate-fade-in-up">
                            <Header 
                                showNewFileButton={true}
                                onNewFile={handleHeaderNewFile}
                                onLoadShiftFile={handleHeaderLoadShift}
                                onClearDepartments={handleClearDepartments}
                                isClearingDepartments={isClearingDepartments}
                                hasDepartmentData={!!departmentMap && Object.keys(departmentMap).length > 0}
                                onClearData={handleClearData}
                                fileInfo={fileInfo}
                                onToggleFilters={() => setIsFilterSidebarOpen(true)}
                            />

                            <main id="dashboard-container" ref={dashboardContainerRef} className="mt-8 space-y-8">
                                {/* Top Section: KPIs & Primary Analytics */}
                                <div className="grid grid-cols-1 gap-8">
                                    {isProcessing ? <KpiCardsSkeleton /> : <KpiCards onUnshippedClick={openUnshippedModal} />}
                                </div>

                                {/* Main Analytics Grid (Bento Style) */}
                                <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
                                    {/* Left Column: Trends & Industry */}
                                    <div className="lg:col-span-8 space-y-8">
                                        {visibleComponents.trendChart && (
                                            <div id="trend-chart-section">
                                                {isProcessing ? <ChartSkeleton /> : <TrendChart />}
                                            </div>
                                        )}
                                        {visibleComponents.industryGrid && (
                                            <div id="industry-grid-section">
                                                {isProcessing ? <ChartSkeleton height="h-[600px]" /> : <IndustryGrid />}
                                            </div>
                                        )}
                                    </div>

                                    {/* Right Column: Key Tables or Widgets */}
                                    <div className="lg:col-span-4 space-y-8">
                                        {processedData.warehouseSummary && processedData.warehouseSummary.length > 0 && (
                                            <WarehouseSummary onBatchExport={logic.handleBatchKhoExport} />
                                        )}
                                        <div className="chart-card p-6 bg-indigo-600 text-white border-none overflow-hidden group">
                                            <div className="absolute -right-4 -bottom-4 opacity-10 group-hover:scale-110 transition-transform duration-700">
                                                <Icon name="sparkles" size={24} />
                                            </div>
                                            <h3 className="text-xl font-black uppercase tracking-tight mb-2 italic">Intelligence Hub AI</h3>
                                            <p className="text-sm text-indigo-100 font-medium leading-relaxed">
                                                Hệ thống đã phân tích dữ liệu bán hàng mới nhất. Nhấn vào nút "Nhận xét AI" ở các bảng để xem chiến lược khai thác gợi ý.
                                            </p>
                                        </div>
                                    </div>
                                </div>

                                {/* Full Width Bottom Section: Deep Analysis */}
                                <div className="space-y-8">
                                    {visibleComponents.employeeAnalysis && (
                                        <div id="employee-analysis-section">
                                            {isProcessing ? <TabbedTableSkeleton /> : <EmployeeAnalysis />}
                                        </div>
                                    )}
                                    {visibleComponents.summaryTable && (
                                        <div id="summary-table-section">
                                            {isProcessing ? <TableSkeleton /> : <SummaryTable />}
                                        </div>
                                    )}
                                </div>
                            </main>

                            <Footer lastUpdated={processedData.lastUpdated} onToggleDebug={() => {}} />
                            <ChatFab onClick={() => setIsChatOpen(true)} />
                        </div>
                    )}

                    {appState === 'loading' && <ProcessingLoader status={status} processingTime={processingTime} />}
                    {isExporting && <ExportLoader />}

                    {/* Modals & Overlays */}
                    {activeModal === 'performance' && processedData && (
                        <PerformanceModal isOpen={true} onClose={() => setActiveModal(null)} employeeName={modalData.employeeName} onExport={handleExport} />
                    )}
                    {activeModal === 'unshipped' && processedData && (
                        <UnshippedOrdersModal isOpen={true} onClose={() => setActiveModal(null)} onExport={handleExport} />
                    )}
                    {isChatOpen && (
                        <ChatModal isOpen={isChatOpen} onClose={() => setIsChatOpen(false)} history={chatHistory} isSending={isAiResponding} onSendMessage={handleSendMessage} />
                    )}

                    {/* Filter Sidebar Overlay */}
                    <div className={`fixed inset-0 z-[150] transition-opacity duration-500 ${isFilterSidebarOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}>
                        <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-sm" onClick={() => setIsFilterSidebarOpen(false)}></div>
                        <div className={`absolute top-0 right-0 h-full w-full max-w-md bg-white dark:bg-slate-900 shadow-2xl transition-transform duration-500 ease-in-out transform ${isFilterSidebarOpen ? 'translate-x-0' : 'translate-x-full'}`}>
                            <FilterSection 
                                options={uniqueFilterOptions} 
                                visibility={visibleComponents} 
                                onVisibilityChange={handleVisibilityChange} 
                                onClose={() => setIsFilterSidebarOpen(false)}
                            />
                        </div>
                    </div>
                </div>
            </div>
        </DashboardContext.Provider>
    );
}

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  body {
    @apply bg-slate-50 text-slate-900 dark:bg-slate-950 dark:text-slate-100 antialiased;
  }
}

@layer components {
  .glass-card {
    @apply bg-white/70 dark:bg-slate-900/70 backdrop-blur-xl border border-white/20 dark:border-slate-800/50 shadow-xl shadow-slate-200/50 dark:shadow-none;
  }

  .surface-card {
    @apply bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[2.5rem] transition-all duration-300;
  }

  .chart-card {
    @apply surface-card p-6 hover:shadow-2xl hover:shadow-indigo-500/10 hover:-translate-y-1;
  }

  .text-gradient {
    @apply bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-purple-600;
  }
}

.animate-fade-in {
  animation: fadeIn 0.6s cubic-bezier(0.16, 1, 0.3, 1) forwards;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}

.hide-scrollbar::-webkit-scrollbar {
  display: none;
}

