import React, { useState, useEffect, useCallback, useRef } from 'react';
import ReactDOM from 'react-dom/client';
import type { AppState, Status, ProcessedData, DataRow, FilterState, ProductConfig, ChatMessage, Employee } from '../types';
import type { Chat } from '@google/genai';
import { loadConfigFromSheet, processShiftFile, DepartmentMap } from '../services/dataService';
import { applyFiltersAndProcess } from '../services/filterService';
import { exportElementAsImage } from '../services/uiService';
import { createChatSession } from '../services/aiService';
import { saveDepartmentMap, getDepartmentMap, clearDepartmentMap, saveSalesData, getSalesData, clearSalesData, getProductConfig, saveProductConfig, clearProductConfig, clearCustomTabs } from '../services/dbService';
import { getRowValue } from '../utils/dataUtils';
import { COL } from '../constants';
import PerformanceModal from '../components/modals/PerformanceModal';

const initialFilterState: FilterState = {
    kho: 'all',
    xuat: 'all',
    trangThai: [],
    nguoiTao: [],
    department: [],
    startDate: '',
    endDate: '',
    dateRange: 'all',
    industryGrid: {
        selectedGroups: [],
        selectedSubgroups: [],
    },
    summaryTable: {
        parent: [],
        child: [],
        manufacturer: [],
        creator: [],
        product: [],
        drilldownOrder: ['manufacturer', 'creator'],
        sort: { column: 'totalRevenue', direction: 'desc' }
    }
};

export const useDashboardLogic = () => {
    const [status, setStatus] = useState<Status>({ message: '', type: 'info', progress: 0 });
    const [appState, setAppState] = useState<AppState>('loading');
    const [isProcessing, setIsProcessing] = useState(false);
    const [isClearingDepartments, setIsClearingDepartments] = useState(false);
    const [isExporting, setIsExporting] = useState(false);
    const [fileInfo, setFileInfo] = useState<{ filename: string; savedAt: string } | null>(null);
    const [processingTime, setProcessingTime] = useState(0);

    const [originalData, setOriginalData] = useState<DataRow[]>([]);
    const [baseFilteredData, setBaseFilteredData] = useState<DataRow[]>([]);
    const [productConfig, setProductConfig] = useState<ProductConfig | null>(null);
    const [departmentMap, setDepartmentMap] = useState<DepartmentMap | null>(null);
    const [processedData, setProcessedData] = useState<ProcessedData | null>(null);
    const [employeeAnalysisData, setEmployeeAnalysisData] = useState<ProcessedData['employeeData'] | null>(null);
    const [configUrl, setConfigUrl] = useState('https://docs.google.com/spreadsheets/d/e/2PACX-1vRhes_lcas8n2_xYHKylsjyD3PIVbdchCiL2XDKJ4OYfgUZlVjAT7ZGWDHrYRzQVrK2w50W86Da3l48/pub?output=csv');
    const [isDeduplicationEnabled, setIsDeduplicationEnabled] = useState(true);

    const [filterState, setFilterState] = useState<FilterState>(() => {
        const saved = localStorage.getItem('industryGridFilters');
        const industryGrid = saved ? JSON.parse(saved) : initialFilterState.industryGrid;
        if (!industryGrid.selectedSubgroups) {
            industryGrid.selectedSubgroups = [];
        }
        return { ...initialFilterState, industryGrid };
    });
    const [uniqueFilterOptions, setUniqueFilterOptions] = useState<{ kho: string[]; trangThai: string[]; nguoiTao: string[], department: string[] }>({ kho: [], trangThai: [], nguoiTao: [], department: [] });

    const [activeModal, setActiveModal] = useState<'performance' | 'unshipped' | null>(null);
    const [modalData, setModalData] = useState<any>(null);

    const [isChatOpen, setIsChatOpen] = useState(false);
    const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
    const [isAiResponding, setIsAiResponding] = useState(false);
    const chatSession = useRef<Chat | null>(null);
    const timerRef = useRef<number | undefined>(undefined);

    const startTimer = () => {
        setProcessingTime(0);
        const startTime = Date.now();
        timerRef.current = window.setInterval(() => {
            setProcessingTime(Date.now() - startTime);
        }, 100);
    };

    const stopTimer = () => {
        if (timerRef.current) {
            clearInterval(timerRef.current);
            timerRef.current = undefined;
        }
    };

    // Initial Data Loading Effect
    useEffect(() => {
        const loadInitialData = async () => {
            setAppState('loading');
            setIsProcessing(true);
            try {
                let config: ProductConfig;
                const cachedConfig = await getProductConfig();
                if (cachedConfig) {
                    config = cachedConfig.config;
                } else {
                    config = await loadConfigFromSheet(configUrl, () => {});
                    await saveProductConfig(config, configUrl);
                }
                setProductConfig(config);

                const savedDeptMap = await getDepartmentMap();
                if (savedDeptMap) setDepartmentMap(savedDeptMap);

                const savedSales = await getSalesData();
                if (savedSales && savedSales.data.length > 0) {
                    setStatus({ message: 'Đang tải dữ liệu đã lưu...', type: 'info', progress: 25 });
                    setFileInfo({ filename: savedSales.filename, savedAt: savedSales.savedAt.toLocaleString('vi-VN') });

                    const rehydratedData = savedSales.data.map(row => ({
                        ...row,
                        parsedDate: row.parsedDate ? new Date(row.parsedDate as string) : null,
                    })).filter(row => row.parsedDate && !isNaN(row.parsedDate.getTime()));

                    setOriginalData(rehydratedData);
                    setAppState('dashboard');
                    setIsProcessing(true);


                    // Silently check for config updates
                    try {
                        const latestConfig = await loadConfigFromSheet(configUrl, () => {});
                        if (JSON.stringify(config) !== JSON.stringify(latestConfig)) {
                            console.log("Phát hiện cấu hình mới, đang tự động cập nhật...");
                            await saveProductConfig(latestConfig, configUrl);
                            setProductConfig(latestConfig);
                        }
                    } catch (updateError) {
                        console.warn("Không thể kiểm tra cập nhật cấu hình tự động:", updateError);
                    }
                } else {
                    setAppState('upload');
                    setIsProcessing(false);
                }
            } catch (e) {
                console.error("Lỗi khi tải dữ liệu ban đầu:", e);
                const msg = e instanceof Error ? e.message : 'Lỗi không xác định khi tải dữ liệu.';
                setStatus({ message: msg, type: 'error', progress: 0 });
                setAppState('upload');
                await Promise.all([clearSalesData(), clearDepartmentMap(), clearProductConfig()]);
                setIsProcessing(false);
            }
        };
        loadInitialData();
    }, [configUrl]);

    // Filter Options Setup Effect
    useEffect(() => {
        if (originalData.length > 0) {
            const khoOptions = [...new Set(originalData.map(r => getRowValue(r, COL.KHO)).filter(Boolean).map(String))];
            const trangThaiOptions = [...new Set(originalData.map(r => getRowValue(r, COL.TRANG_THAI)).filter(Boolean).map(String))];
            const nguoiTaoOptions = [...new Set(originalData.map(r => getRowValue(r, COL.NGUOI_TAO)).filter(Boolean).map(String))];

            let deptOptions: string[] = [];
            if(departmentMap) {
                const uniqueDepartments = Array.from(new Set(Object.values(departmentMap).map(String))).sort();
                const excludedKeywords = ['quản lý', 'trưởng ca', 'kế toán', 'tiếp đón khách hàng'];
                deptOptions = uniqueDepartments.filter(d => !excludedKeywords.some(keyword => d.toLowerCase().includes(keyword)));
            }

            setUniqueFilterOptions({ kho: khoOptions, trangThai: trangThaiOptions, nguoiTao: nguoiTaoOptions, department: deptOptions });
            setFilterState(prev => ({ ...prev, trangThai: trangThaiOptions, nguoiTao: nguoiTaoOptions, department: deptOptions }));
        }
    }, [originalData, departmentMap]);

    const handleFilterChange = useCallback((newFilters: Partial<FilterState>) => {
        setFilterState(prev => {
            const updated = { ...prev, ...newFilters };
            if (newFilters.industryGrid) {
                updated.industryGrid = { ...prev.industryGrid, ...newFilters.industryGrid };
                localStorage.setItem('industryGridFilters', JSON.stringify(updated.industryGrid));
            }
            if (newFilters.summaryTable) {
                updated.summaryTable = { ...prev.summaryTable, ...newFilters.summaryTable };
            }
            return updated;
        });
    }, []);

    // Central Data Processing Effect
    useEffect(() => {
        if (appState !== 'dashboard' || !originalData.length || !productConfig) return;

        setIsProcessing(true);
        const timer = setTimeout(() => {
            try {
                const { processedData: result, baseFilteredData: newBaseData } = applyFiltersAndProcess(originalData, productConfig, filterState, departmentMap);
                setProcessedData(result);
                setBaseFilteredData(newBaseData);

                if (departmentMap) {
                    const employeeFilterState = { ...filterState, department: [] };
                    const { processedData: employeeResult } = applyFiltersAndProcess(originalData, productConfig, employeeFilterState, departmentMap);
                    setEmployeeAnalysisData(employeeResult.employeeData);
                } else {
                    setEmployeeAnalysisData(result.employeeData);
                }
                // Dòng thông báo thành công đã được ẩn đi để giảm sự gián đoạn
            } catch (error) {
                console.error("Lỗi khi xử lý lại dữ liệu:", error);
                setStatus({ message: "Đã xảy ra lỗi trong quá trình xử lý dữ liệu.", type: 'error', progress: 0 });
                setAppState('upload');
            } finally {
                setIsProcessing(false);
            }
        }, 100);

        return () => clearTimeout(timer);
    }, [appState, originalData, productConfig, filterState, departmentMap]);

    // Reset Chat Session Effect
    useEffect(() => {
        chatSession.current = null;
        setChatHistory([]);
    }, [processedData]);

    const openPerformanceModal = (employeeName: string) => {
        setModalData({ employeeName });
        setActiveModal('performance');
    };

    const handleBatchExport = async (employeesToExport: Employee[]) => {
        if (!employeesToExport.length || !productConfig || !processedData) return;
        setIsExporting(true);
        const offscreenContainer = document.createElement('div');
        offscreenContainer.style.cssText = 'position: absolute; left: -9999px; top: 0;';
        document.body.appendChild(offscreenContainer);
        const root = ReactDOM.createRoot(offscreenContainer);
        try {
            for (const employee of employeesToExport) {
                await new Promise<void>(resolve => {
                    root.render(
                        React.createElement(PerformanceModal, {
                            isOpen: true,
                            onClose: () => {},
                            employeeName: employee.name,
                            fullSellerArray: processedData.employeeData.fullSellerArray,
                            validSalesData: processedData.filteredValidSalesData,
                            productConfig: productConfig,
                            onExport: exportElementAsImage,
                            isBatchExporting: true
                        })
                    );
                    setTimeout(resolve, 1000);
                });
                const modalContent = offscreenContainer.querySelector('.modal-content');
                if (modalContent) {
                    const filename = `phan-tich-hieu-qua-${employee.name.replace(/[^a-zA-Z0-9]/g, '_')}.png`;
                    await exportElementAsImage(modalContent as HTMLElement, filename, { scale: 2, forceOpenDetails: true });
                }
            }
        } finally {
            setIsExporting(false);
            root.unmount();
            document.body.removeChild(offscreenContainer);
        }
    };

    const handleBatchKhoExport = async () => {
        if (uniqueFilterOptions.kho.length <= 1) {
            setStatus({ message: 'Chỉ có một kho, không thể xuất hàng loạt.', type: 'error', progress: 0 });
            return;
        }

        setIsExporting(true);
        const originalKho = filterState.kho;

        try {
            const khosToExport = uniqueFilterOptions.kho.filter(k => k && k !== 'all');
            const overviewElement = document.getElementById('business-overview');
            const warehouseElement = document.getElementById('warehouse-summary-view');

            if (!overviewElement || !warehouseElement) {
                throw new Error('Không tìm thấy thành phần cần xuất (#business-overview or #warehouse-summary-view).');
            }

            for (const kho of khosToExport) {
                handleFilterChange({ kho });
                await new Promise(resolve => setTimeout(resolve, 1500));

                let rowToHighlight: Element | null = warehouseElement.querySelector(`tr[data-kho-id="${kho}"]`);
                if (rowToHighlight) {
                    rowToHighlight.classList.add('is-highlighted-for-export');
                }

                await new Promise(resolve => setTimeout(resolve, 200)); // Short delay for highlight to render

                // Export #1: Business Overview
                await exportElementAsImage(overviewElement, `tong-quan-kinh-doanh-${kho}.png`, {
                    elementsToHide: ['.hide-on-export'],
                    captureAsDisplayed: false,
                    isCompactTable: true,
                    forcedWidth: 700,
                });

                // Export #2: Warehouse Summary
                await exportElementAsImage(warehouseElement, `bao-cao-kho-${kho}.png`, {
                    elementsToHide: ['.hide-on-export'],
                    captureAsDisplayed: true,
                });

                if (rowToHighlight) {
                    rowToHighlight.classList.remove('is-highlighted-for-export');
                }
            }
        } catch (error) {
            console.error("Lỗi khi xuất hàng loạt theo kho:", error);
            setStatus({ message: 'Đã xảy ra lỗi trong quá trình xuất hàng loạt.', type: 'error', progress: 0 });
        } finally {
            handleFilterChange({ kho: originalKho });
            await new Promise(resolve => setTimeout(resolve, 1500)); 
            setIsExporting(false);
        }
    };

    const handleClearDepartments = async () => {
        setIsClearingDepartments(true);
        try {
            await clearDepartmentMap();
            setDepartmentMap(null);
        } catch (error) {
            console.error(error);
        } finally {
            setIsClearingDepartments(false);
        }
    };

    const handleClearData = async () => {
        try {
            await clearSalesData();
            await clearCustomTabs();
            setOriginalData([]);
            setProcessedData(null);
            setFileInfo(null);
            setAppState('upload');
        } catch (error) {
            console.error(error);
        }
    };

    const handleShiftFileProcessing = async (files: File[]) => {
        if (files.length === 0) return;
        setAppState('loading');
        setIsProcessing(true);
        setStatus({ message: `Đang xử lý ${files.length} file phân ca...`, type: 'info', progress: 20 });
        try {
            let mergedMap: DepartmentMap = (await getDepartmentMap()) || {}; // Start with saved data if available

            for (let i = 0; i < files.length; i++) {
                const file = files[i];
                setStatus({ message: `Đang xử lý file ${i + 1}/${files.length}: ${file.name}`, type: 'info', progress: 20 + (60 * (i + 1) / files.length) });
                const { map } = await processShiftFile(file); 
                mergedMap = { ...mergedMap, ...map }; // Merge the new map, overwriting duplicates
            }

            await saveDepartmentMap(mergedMap);
            setDepartmentMap(mergedMap);
            setStatus({ message: `Đã xử lý và gộp ${files.length} file phân ca!`, type: 'success', progress: 100 });
        } catch (error) {
            const msg = error instanceof Error ? error.message : "Lỗi không xác định";
            setStatus({ message: msg, type: 'error', progress: 0 });
        } finally {
            setIsProcessing(false);
            if(originalData.length > 0) setAppState('dashboard');
            else setAppState('upload');
        }
    };

    const handleFileProcessing = async (file: File) => {
        setAppState('loading');
        setIsProcessing(true);
        startTimer();
        setStatus({ message: 'Khởi tạo tác vụ nền...', type: 'info', progress: 0 });

        if (!window.Worker) {
            setStatus({ message: 'Trình duyệt của bạn không hỗ trợ xử lý nền (Web Workers).', type: 'error', progress: 0 });
            setAppState('upload');
            setIsProcessing(false);
            stopTimer();
            return;
        }

        const worker = new Worker(new URL('../services/worker.ts', import.meta.url), { type: 'module' });

        worker.onmessage = async (e: MessageEvent<{ type: string, payload: any }>) => {
            const { type, payload } = e.data;

            if (type === 'progress') {
                setStatus(payload);
            } else if (type === 'result') {
                const data = payload as DataRow[];
                setStatus({ message: 'Đang lưu dữ liệu...', type: 'info', progress: 95 });
                await saveSalesData(data, file.name);
                setFileInfo({ filename: file.name, savedAt: new Date().toLocaleString('vi-VN') });
                setOriginalData(data);
                setStatus({ message: 'Đang tổng hợp báo cáo...', type: 'info', progress: 98 });
                setAppState('dashboard');
                worker.terminate();
                stopTimer();
            } else if (type === 'error') {
                setStatus({ message: payload, type: 'error', progress: 0 });
                setAppState('upload');
                setIsProcessing(false);
                worker.terminate();
                stopTimer();
            }
        };

        worker.onerror = (e) => {
            console.error('Lỗi Worker:', e);
            setStatus({ message: `Lỗi tác vụ nền: ${e.message}`, type: 'error', progress: 0 });
            setAppState('upload');
            setIsProcessing(false);
            worker.terminate();
            stopTimer();
        };

        worker.postMessage({ file, enableDeduplication: isDeduplicationEnabled });
    };

    const handleSendMessage = useCallback(async (message: string) => {
        if (!processedData) return;

        setIsAiResponding(true);
        setChatHistory(prev => [...prev, { role: 'user', content: message }]);

        if (!chatSession.current) {
            chatSession.current = createChatSession(processedData);
        }

        try {
            const result = await chatSession.current.sendMessage({ message });
            setChatHistory(prev => [...prev, { role: 'model', content: result.text }]);
        } catch (error) {
            console.error("AI chat error:", error);
            setChatHistory(prev => [...prev, { role: 'model', content: "Xin lỗi, đã có lỗi xảy ra. Vui lòng thử lại." }]);
        } finally {
            setIsAiResponding(false);
        }
    }, [processedData]);

    const openUnshippedModal = () => setActiveModal('unshipped');

    const handleExport = async (element: HTMLElement | null, filename: string, options: any = {}) => {
        if (element) {
            setIsExporting(true);
            const exportOptions = {
                elementsToHide: ['.hide-on-export'],
                ...options
            };
            await exportElementAsImage(element, filename, exportOptions);
            setIsExporting(false);
        }
    };

    const handleDeduplicationChange = (enabled: boolean) => {
        setIsDeduplicationEnabled(enabled);
    };

    return {
        status, appState, isProcessing, isClearingDepartments, isExporting, fileInfo,
        departmentMap, originalData, baseFilteredData, productConfig, processedData, employeeAnalysisData,
        configUrl, setConfigUrl, uniqueFilterOptions,
        filterState, handleFilterChange,
        activeModal, setActiveModal, modalData,
        isChatOpen, setIsChatOpen, chatHistory, isAiResponding,
        handleClearDepartments, handleClearData, handleShiftFileProcessing, handleFileProcessing,
        handleSendMessage, openPerformanceModal, openUnshippedModal, handleExport,
        handleBatchExport,
        handleBatchKhoExport,
        isDeduplicationEnabled,
        handleDeduplicationChange,
        processingTime
    };
};

import type { DataRow, ProductConfig, Status } from '../types';
import { getRowValue, parseExcelDate } from '../utils/dataUtils';
import { COL } from '../constants';
import * as XLSX from 'xlsx';

type StatusUpdater = (status: Status) => void;

export type DepartmentMap = { [employeeId: string]: string };

function robustCsvParse(text: string): string[][] {
    const lines = text.split(/\r?\n/);
    const result: string[][] = [];

    for (const line of lines) {
        if (!line.trim()) continue;

        const row: string[] = [];
        let cell = '';
        let inQuotes = false;

        for (let i = 0; i < line.length; i++) {
            const char = line[i];

            if (char === '"') {
                if (inQuotes && i + 1 < line.length && line[i + 1] === '"') {
                    // Handle escaped quote ""
                    cell += '"';
                    i++; // Skip next quote
                } else {
                    inQuotes = !inQuotes;
                }
            } else if (char === ',' && !inQuotes) {
                row.push(cell.trim());
                cell = '';
            } else {
                cell += char;
            }
        }
        row.push(cell.trim());
        result.push(row);
    }
    return result;
}


export async function loadConfigFromSheet(url: string, setStatus: StatusUpdater): Promise<ProductConfig> {
    setStatus({ message: 'Đang tải file cấu hình...', type: 'info', progress: 0 });
    try {
        const response = await fetch(url);
        if (!response.ok) {
            throw new Error(`Không thể tải file cấu hình. Status: ${response.status}`);
        }
        const csvText = await response.text();
        setStatus({ message: 'Đang xử lý file cấu hình...', type: 'info', progress: 50 });

        const parsedRows = robustCsvParse(csvText);

        if (parsedRows.length < 2) {
             throw new Error('File cấu hình không hợp lệ hoặc không có dữ liệu.');
        }

        const headers = parsedRows[0].map(h => h.trim());
        const data = parsedRows.slice(1);

        const config: ProductConfig = {
            groups: {},
            subgroups: {},
            childToParentMap: {},
            childToSubgroupMap: {}
        };

        const groupIndex = headers.indexOf('NhomCha');
        const subgroupIndex = headers.indexOf('NhomCon');
        const productCodeIndex = headers.indexOf('NhomHang');

        if (groupIndex === -1 || subgroupIndex === -1 || productCodeIndex === -1) {
            console.error('Headers found:', headers);
            throw new Error('File cấu hình thiếu các cột bắt buộc: NhomCha, NhomCon, NhomHang');
        }

        data.forEach(row => {
            if (row.length > Math.max(groupIndex, subgroupIndex, productCodeIndex)) {
                const parentGroup = row[groupIndex];
                const childGroup = row[subgroupIndex];
                const productCode = row[productCodeIndex];

                if (parentGroup && childGroup && productCode) {
                    if (!config.groups[parentGroup]) {
                        config.groups[parentGroup] = new Set();
                    }
                    config.groups[parentGroup].add(productCode);

                    if (!config.subgroups[parentGroup]) {
                        config.subgroups[parentGroup] = {};
                    }
                    if (!config.subgroups[parentGroup][childGroup]) {
                        config.subgroups[parentGroup][childGroup] = [];
                    }
                    config.subgroups[parentGroup][childGroup].push(productCode);

                    config.childToParentMap[productCode] = parentGroup;
                    config.childToSubgroupMap[productCode] = childGroup;
                }
            }
        });

        if (Object.keys(config.groups).length === 0) {
            throw new Error("Không thể xử lý dữ liệu từ file cấu hình. Vui lòng kiểm tra định dạng.");
        }

        setStatus({ message: 'Tải cấu hình thành công.', type: 'success', progress: 100 });
        return config;
    } catch (error) {
        console.error("Lỗi khi tải cấu hình:", error);
        const errorMessage = error instanceof Error ? error.message : "Lỗi không xác định khi tải cấu hình";
        setStatus({ message: errorMessage, type: 'error', progress: 0 });
        throw error;
    }
}

export async function processShiftFile(file: File): Promise<{ map: DepartmentMap, uniqueDepartments: string[] }> {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = (e: ProgressEvent<FileReader>) => {
            try {
                if (!e.target?.result) throw new Error("Không thể đọc file phân ca.");

                const data = new Uint8Array(e.target.result as ArrayBuffer);
                const workbook = XLSX.read(data, { type: 'array' });
                const sheetName = workbook.SheetNames[0];
                const worksheet = workbook.Sheets[sheetName];
                const rows: any[][] = XLSX.utils.sheet_to_json(worksheet, { header: 1, defval: null });

                const map: DepartmentMap = {};
                let currentDepartment: string | null = null;
                const departments = new Set<string>();

                for (let i = 1; i < rows.length; i++) {
                    const row = rows[i];
                    if (row[0] && typeof row[0] === 'string' && row[0].trim() !== '') {
                        currentDepartment = row[0].trim();
                    }

                    const userId = row[1];

                    if (userId && currentDepartment) {
                        const userIdStr = String(userId).trim();
                        // Chuẩn hóa ID: Nếu file có dạng "12345 - Tên", chỉ lấy "12345" để làm key
                        const cleanId = userIdStr.split(' - ')[0].trim();
                        if (cleanId) {
                             map[cleanId] = currentDepartment;
                             departments.add(currentDepartment);
                        }
                    }
                }

                if (Object.keys(map).length === 0) {
                    throw new Error("File phân ca không hợp lệ hoặc không chứa dữ liệu nhân viên và bộ phận.");
                }

                resolve({ map, uniqueDepartments: Array.from(departments).sort() });

            } catch (error) {
                console.error("Lỗi khi xử lý file phân ca:", error);
                const errorMessage = error instanceof Error ? error.message : "Lỗi không xác định khi xử lý file phân ca";
                reject(new Error(errorMessage));
            }
        };
        reader.onerror = (error) => reject(error);
        reader.readAsArrayBuffer(file);
    });
}

import type { DataRow, ProductConfig, Employee, EmployeeData, ExploitationData } from '../types';
import { COL, HINH_THUC_XUAT_THU_HO } from '../constants';
import { getRowValue, getHeSoQuyDoi, getDisplayParentGroup, getHinhThucThanhToan } from '../utils/dataUtils';
import { DepartmentMap } from './dataService';

function _buildFullEmployeeData(
    employeeStats: { [key: string]: Partial<Employee> & { name: string, customerSet: Set<string>, totalOrders: number, doanhThuTraCham: number, slCE_ICT: number, slTraCham_CE_ICT: number, doanhThu_CE_ICT: number, doanhThuTraCham_CE_ICT: number } },
    exploitationStats: { [creator: string]: Partial<ExploitationData> & { name: string } },
    periodData: DataRow[],
    employeeIndustryStats: { [creator: string]: { [industry: string]: number } },
    employeeDailyTrend: { [creator: string]: { [date: string]: number } },
    departmentMap: DepartmentMap | null
): EmployeeData {

    const allCreatorsInPeriod = new Set(periodData.map(r => getRowValue(r, COL.NGUOI_TAO)).filter(Boolean));

    allCreatorsInPeriod.forEach(creator => {
        const creatorThuHoCount = periodData.filter(r => getRowValue(r, COL.NGUOI_TAO) === creator && HINH_THUC_XUAT_THU_HO.has(getRowValue(r, COL.HINH_THUC_XUAT))).length;

        if (employeeStats[creator]) {
             employeeStats[creator].slThuHo = (employeeStats[creator].slThuHo || 0) + creatorThuHoCount;
        } else if (creatorThuHoCount > 0) {
             employeeStats[creator] = { name: creator, doanhThuThuc: 0, doanhThuQD: 0, slTraCham: 0, doanhThuTraCham: 0, slThuHo: creatorThuHoCount, customerSet: new Set(), totalOrders: 0, slCE_ICT: 0, slTraCham_CE_ICT: 0, doanhThu_CE_ICT: 0, doanhThuTraCham_CE_ICT: 0 };
        }

        if (exploitationStats[creator] === undefined && employeeStats[creator] !== undefined) {
             exploitationStats[creator] = { name: creator };
        }

        if (departmentMap && (employeeStats[creator] || exploitationStats[creator])) {
            const creatorId = creator.split(' - ')[0].trim();
            const dept = departmentMap[creatorId];
            if (dept) {
                if (employeeStats[creator]) employeeStats[creator].department = dept;
                if (exploitationStats[creator]) exploitationStats[creator].department = dept;
            }
        }
    });

    let finalEmployeeStats = employeeStats;
    let finalExploitationStats = exploitationStats;
    let finalIndustryStats = employeeIndustryStats;
    let finalDailyTrend = employeeDailyTrend;

    if (departmentMap && Object.keys(departmentMap).length > 0) {
        const employeeIdsInMap = new Set(Object.keys(departmentMap));
        const filterPredicate = ([creator, _]: [string, any]) => {
            // Logic cũ: Chỉ giữ lại những người CÓ trong map (nếu map tồn tại)
            // Tuy nhiên, để hiển thị đầy đủ, ta giữ lại tất cả những người trong stats (đã được merge ở bước trước)
            // nhưng gán bộ phận chính xác.
            // Đoạn này thực ra dùng để lọc bớt những người "lạ" không có trong phân ca nếu muốn strict mode.
            // Hiện tại chúng ta cho phép hiển thị tất cả, nhưng ưu tiên map.
            // Để an toàn và hiển thị cả nhân viên cũ/mới chưa kịp cập nhật phân ca, ta KHÔNG lọc bỏ người có doanh thu.
            // Nhưng ta sẽ lọc để nhóm theo bộ phận chính xác.
            return true; 
        };

        // Sắp xếp lại logic: Nếu dùng filterPredicate dựa trên map, những người có doanh thu mà không có trong map sẽ bị mất.
        // Để hiển thị đúng "Phân ca", ta nên ưu tiên những người có trong map.
        // Những người không có trong map nhưng có doanh thu -> Vẫn hiển thị (Department = Không phân ca).

        // Do đó, ta không cần filter ở đây nữa, vì employeeStats đã chứa cả người có doanh thu + người từ map (được thêm ở processEmployeeData).
        // Chỉ cần đảm bảo department được gán đúng (đã làm ở trên).
    }

    const fullSellerArray: Employee[] = Object.values(finalEmployeeStats).map(emp => {
        const doanhThuThuc = emp.doanhThuThuc || 0;
        const doanhThuQD = emp.doanhThuQD || 0;
        const slTraCham = emp.slTraCham || 0;
        const doanhThuTraCham = emp.doanhThuTraCham || 0;
        const slTiepCan = emp.customerSet ? emp.customerSet.size : 0;
        const totalOrders = emp.totalOrders || 0;
        const slCE_ICT = emp.slCE_ICT || 0;
        const slTraCham_CE_ICT = emp.slTraCham_CE_ICT || 0;
        const doanhThu_CE_ICT = emp.doanhThu_CE_ICT || 0;
        const doanhThuTraCham_CE_ICT = emp.doanhThuTraCham_CE_ICT || 0;

        return {
            name: emp.name,
            department: emp.department || 'Không Phân Ca',
            doanhThuThuc,
            doanhThuQD,
            doanhThuTraCham,
            hieuQuaValue: doanhThuThuc > 0 ? ((doanhThuQD - doanhThuThuc) / doanhThuThuc) * 100 : 0,
            slTiepCan,
            aov: slTiepCan > 0 ? doanhThuThuc / slTiepCan : 0,
            slThuHo: emp.slThuHo || 0,
            slTraCham,
            totalOrders: totalOrders,
            traChamPercent: doanhThuThuc > 0 ? (doanhThuTraCham / doanhThuThuc) * 100 : 0,
            slCE_ICT,
            slTraCham_CE_ICT,
            traChamPercent_CE_ICT: slCE_ICT > 0 ? (slTraCham_CE_ICT / slCE_ICT) * 100 : 0,
            doanhThu_CE_ICT,
            doanhThuTraCham_CE_ICT,
            dtTraChamPercent_CE_ICT: doanhThu_CE_ICT > 0 ? (doanhThuTraCham_CE_ICT / doanhThu_CE_ICT) * 100 : 0,
            weakPointsRevenue: 0,
            weakPointsExploitation: 0,
        };
    });

    const exploitationData: ExploitationData[] = Object.values(finalExploitationStats)
        .filter(ex => ex.name)
        .map(ex => {
            const doanhThuThuc = ex.doanhThuThuc || 0;
            const doanhThuQD = ex.doanhThuQD || 0;
            const slBaoHiem = ex.slBaoHiem || 0;
            const slSPChinh_Tong = (ex.slICT || 0) + (ex.slCE_main || 0) + (ex.slGiaDung_main || 0);
            return {
                name: ex.name!,
                department: ex.department || 'Không Phân Ca',
                doanhThuThuc,
                doanhThuQD,
                hieuQuaQD: doanhThuThuc > 0 ? (doanhThuQD - doanhThuThuc) / doanhThuThuc * 100 : 0,

                slICT: ex.slICT || 0,
                doanhThuICT: ex.doanhThuICT || 0,
                slCE_main: ex.slCE_main || 0,
                doanhThuCE_main: ex.doanhThuCE_main || 0,
                slGiaDung_main: ex.slGiaDung_main || 0,

                slBaoHiem,
                doanhThuBaoHiem: ex.doanhThuBaoHiem || 0,
                percentBaoHiem: slSPChinh_Tong > 0 ? (slBaoHiem / slSPChinh_Tong) * 100 : 0,
                slSim: ex.slSim || 0,
                doanhThuSim: ex.doanhThuSim || 0,
                slDongHo: ex.slDongHo || 0,
                doanhThuDongHo: ex.doanhThuDongHo || 0,
                doanhThuPhuKien: ex.doanhThuPhuKien || 0,
                slPhuKien: ex.slPhuKien || 0,
                slCamera: ex.slCamera || 0,
                slLoa: ex.slLoa || 0,
                slPinSDP: ex.slPinSDP || 0,
                slTaiNgheBLT: ex.slTaiNgheBLT || 0,
                doanhThuGiaDung: ex.doanhThuGiaDung || 0,
                slGiaDung: ex.slGiaDung || 0,
                slMayLocNuoc: ex.slMayLocNuoc || 0,
                slNoiCom: ex.slNoiCom || 0,
                slNoiChien: ex.slNoiChien || 0,
                slQuatDien: ex.slQuatDien || 0,
            };
    });

    const sellersWithSales = fullSellerArray.filter(s => s.doanhThuThuc > 0);
    const totalSellersWithSales = sellersWithSales.length;

    return {
        fullSellerArray,
        exploitationData,
        byIndustry: finalIndustryStats,
        dailyTrend: finalDailyTrend,
        averages: {
            doanhThuThuc: sellersWithSales.reduce((sum, s) => sum + s.doanhThuThuc, 0) / (totalSellersWithSales || 1),
            doanhThuQD: sellersWithSales.reduce((sum, s) => sum + s.doanhThuQD, 0) / (totalSellersWithSales || 1),
            hieuQuaValue: sellersWithSales.reduce((sum, s) => sum + s.hieuQuaValue, 0) / (totalSellersWithSales || 1),
        },
        maxValues: {
            doanhThuThuc: Math.max(0, ...sellersWithSales.map(s => s.doanhThuThuc)),
            doanhThuQD: Math.max(0, ...sellersWithSales.map(s => s.doanhThuQD)),
        },
    };
}


export function processEmployeeData(
    salesData: DataRow[],
    periodData: DataRow[],
    productConfig: ProductConfig,
    departmentMap: DepartmentMap | null
): EmployeeData {

    const employeeStats: { [creator: string]: Partial<Employee> & { name: string, customerSet: Set<string>, totalOrders: number, doanhThuTraCham: number, slCE_ICT: number, slTraCham_CE_ICT: number, doanhThu_CE_ICT: number, doanhThuTraCham_CE_ICT: number } } = {};
    const exploitationStats: { [creator: string]: Partial<ExploitationData> & { name: string } } = {};
    const employeeIndustryStats: { [creator: string]: { [industry: string]: number } } = {};
    const employeeDailyTrend: { [creator: string]: { [date: string]: number } } = {};

    salesData.forEach(row => {
        const creator = getRowValue(row, COL.NGUOI_TAO);
        if (!creator) return;

        const price = Number(getRowValue(row, COL.PRICE)) || 0;
        const quantity = Number(getRowValue(row, COL.QUANTITY)) || 0;
        const revenue = price; // Doanh thu là giá trị của cột Giá bán_1
        const maNganhHang = getRowValue(row, COL.MA_NGANH_HANG);
        const maNhomHang = getRowValue(row, COL.MA_NHOM_HANG);
        const productName = getRowValue(row, COL.PRODUCT);

        const heso = getHeSoQuyDoi(maNganhHang, maNhomHang, productConfig, productName);
        const revenueQD = revenue * heso;
        const customer = getRowValue(row, COL.CUSTOMER_NAME);
        const dateCreated: Date = row.parsedDate;
        const dateKey = dateCreated.toISOString().split('T')[0];

        // --- Initialize stats objects ---
        if (!employeeStats[creator]) employeeStats[creator] = { name: creator, doanhThuThuc: 0, doanhThuQD: 0, slTraCham: 0, doanhThuTraCham: 0, customerSet: new Set(), totalOrders: 0, slCE_ICT: 0, slTraCham_CE_ICT: 0, doanhThu_CE_ICT: 0, doanhThuTraCham_CE_ICT: 0 };
        if (!exploitationStats[creator]) exploitationStats[creator] = { name: creator, slICT: 0, doanhThuICT: 0, slCE_main: 0, doanhThuCE_main: 0, slGiaDung_main: 0, slBaoHiem: 0, doanhThuBaoHiem: 0, slSim: 0, doanhThuSim: 0, slDongHo: 0, doanhThuDongHo: 0, doanhThuPhuKien: 0, slPhuKien: 0, slCamera: 0, slLoa: 0, slPinSDP: 0, slTaiNgheBLT: 0, doanhThuGiaDung: 0, slGiaDung: 0, slMayLocNuoc: 0, slNoiCom: 0, slNoiChien: 0, slQuatDien: 0 };
        if (!employeeIndustryStats[creator]) employeeIndustryStats[creator] = {};
        if (!employeeDailyTrend[creator]) employeeDailyTrend[creator] = {};
        if (!employeeDailyTrend[creator][dateKey]) employeeDailyTrend[creator][dateKey] = 0;

        // Logic trọng số cho Vieon khi tính số lượng
        const subgroup = productConfig.childToSubgroupMap[maNhomHang];
        const isVieon = subgroup === 'Vieon' || (productName || '').toString().includes('VieON');
        const weightedQuantity = isVieon ? (quantity * heso) : quantity;

        // --- Aggregate general stats ---
        const emp = employeeStats[creator];
        emp.doanhThuThuc! += revenue;
        emp.doanhThuQD! += revenueQD;
        emp.totalOrders! += 1;
        if (customer) emp.customerSet.add(customer);
        if (getHinhThucThanhToan(row) === 'tra_gop') {
            emp.slTraCham! += weightedQuantity; // Cập nhật số lượng trọng số
            emp.doanhThuTraCham! += revenue;
        }

        const parentGroupForPerf = productConfig.childToParentMap[maNhomHang] || 'Không xác định';
        if (parentGroupForPerf === 'CE' || parentGroupForPerf === 'ICT') {
            emp.slCE_ICT! += weightedQuantity; // Cập nhật số lượng trọng số
            emp.doanhThu_CE_ICT! += revenue;
            if (getHinhThucThanhToan(row) === 'tra_gop') {
                emp.slTraCham_CE_ICT! += weightedQuantity; // Cập nhật số lượng trọng số
                emp.doanhThuTraCham_CE_ICT! += revenue;
            }
        }

        // --- Aggregate industry stats ---
        const displayGroup = getDisplayParentGroup(maNhomHang, productConfig);
        employeeIndustryStats[creator][displayGroup] = (employeeIndustryStats[creator][displayGroup] || 0) + revenue;
        employeeDailyTrend[creator][dateKey] += revenueQD;

        // --- Aggregate exploitation stats ---
        const stats = exploitationStats[creator];
        stats.doanhThuThuc = (stats.doanhThuThuc || 0) + revenue;
        stats.doanhThuQD = (stats.doanhThuQD || 0) + revenueQD;

        const parentGroup = productConfig.childToParentMap[maNhomHang] || 'Không xác định';
        const childGroup = productConfig.childToSubgroupMap[maNhomHang] || 'Không xác định';

        // SP Chính
        if (parentGroup === 'ICT') {
            stats.slICT! += weightedQuantity;
            stats.doanhThuICT! += revenue;
        } else if (parentGroup === 'CE') {
            stats.slCE_main! += weightedQuantity;
            stats.doanhThuCE_main! += revenue;
        } else if (parentGroup === 'Gia dụng') {
            stats.slGiaDung_main! += weightedQuantity; 
        }

        // Bán Kèm & Các nhóm khác
        if (parentGroup === 'Bảo hiểm') {
            stats.slBaoHiem! += weightedQuantity;
            stats.doanhThuBaoHiem! += revenue;
        } else if (parentGroup === 'Sim') {
            stats.slSim! += weightedQuantity;
            stats.doanhThuSim! += revenue;
        } else if (parentGroup === 'Đồng hồ' || parentGroup === 'Wearable') { 
            stats.slDongHo! += weightedQuantity;
            stats.doanhThuDongHo! += revenue;
        } else if (parentGroup === 'Phụ kiện') {
            stats.doanhThuPhuKien! += revenue;
            stats.slPhuKien! += weightedQuantity; 
            if (childGroup === 'Camera') stats.slCamera! += weightedQuantity;
            else if (childGroup === 'Loa') stats.slLoa! += weightedQuantity;
            else if (childGroup === 'Pin SDP') stats.slPinSDP! += weightedQuantity;
            else if (childGroup === 'Tai nghe BLT') stats.slTaiNgheBLT! += weightedQuantity;
        } else if (parentGroup === 'Gia dụng') {
            stats.doanhThuGiaDung! += revenue;
            stats.slGiaDung! += weightedQuantity; 
            if (childGroup === 'Máy lọc nước') stats.slMayLocNuoc! += weightedQuantity;
            else if (childGroup === 'NC đ.tử/cao tần' || childGroup === 'NC nắp gài/rời') stats.slNoiCom! += weightedQuantity;
            else if (childGroup === 'Nồi chiên') stats.slNoiChien! += weightedQuantity;
            else if (childGroup === 'Quạt điện') stats.slQuatDien! += weightedQuantity;
        }
    });

    // --- Merge employees from DepartmentMap (Shift File) who have NO SALES ---
    if (departmentMap) {
        // Create a set of IDs that already exist in the sales data (to avoid duplicates)
        // Sales data usually has format "ID - Name", so we extract ID
        const existingIds = new Set<string>();
        Object.keys(employeeStats).forEach(key => {
            const id = key.split(' - ')[0].trim();
            existingIds.add(id);
        });

        for (const [empId, dept] of Object.entries(departmentMap)) {
            // Trim ID just in case
            const cleanId = empId.trim();

            if (!existingIds.has(cleanId)) {
                // This employee is in the shift file but has no sales data
                // We add them with 0 performance so they show up in the "Outstanding" table
                // Since we don't have the name from sales data, we use the ID as the name
                employeeStats[cleanId] = {
                    name: cleanId,
                    department: dept,
                    doanhThuThuc: 0,
                    doanhThuQD: 0,
                    slTraCham: 0,
                    doanhThuTraCham: 0,
                    customerSet: new Set(),
                    totalOrders: 0,
                    slCE_ICT: 0,
                    slTraCham_CE_ICT: 0,
                    doanhThu_CE_ICT: 0,
                    doanhThuTraCham_CE_ICT: 0,
                    slThuHo: 0,
                };

                // Initialize empty exploitation stats for safety (though not strictly needed for Outstanding table)
                exploitationStats[cleanId] = {
                    name: cleanId,
                    department: dept,
                    slICT: 0, doanhThuICT: 0, slCE_main: 0, doanhThuCE_main: 0, slGiaDung_main: 0,
                    slBaoHiem: 0, doanhThuBaoHiem: 0, slSim: 0, doanhThuSim: 0, slDongHo: 0, doanhThuDongHo: 0,
                    doanhThuPhuKien: 0, slPhuKien: 0, slCamera: 0, slLoa: 0, slPinSDP: 0, slTaiNgheBLT: 0,
                    doanhThuGiaDung: 0, slGiaDung: 0, slMayLocNuoc: 0, slNoiCom: 0, slNoiChien: 0, slQuatDien: 0
                };

                employeeIndustryStats[cleanId] = {};
                employeeDailyTrend[cleanId] = {};
            }
        }
    }

    const initialEmployeeData = _buildFullEmployeeData(employeeStats, exploitationStats, periodData, employeeIndustryStats, employeeDailyTrend, departmentMap);

    // --- Calculate Weakness Points ---
    const employeesByDept: { [key: string]: Employee[] } = {};
    initialEmployeeData.fullSellerArray.forEach(emp => {
        if (!employeesByDept[emp.department]) {
            employeesByDept[emp.department] = [];
        }
        employeesByDept[emp.department].push(emp);
    });

    const deptThresholds: { [key: string]: any } = {};
    for (const dept in employeesByDept) {
        const deptEmployees = employeesByDept[dept];
        const count = deptEmployees.length;
        if (count > 0) {
            deptThresholds[dept] = {
                dtqd_40p: [...deptEmployees].sort((a, b) => a.doanhThuQD - b.doanhThuQD)[Math.floor(count * 0.4)]?.doanhThuQD,
                slCE_ICT_30p: [...deptEmployees].sort((a, b) => a.slCE_ICT - b.slCE_ICT)[Math.floor(count * 0.3)]?.slCE_ICT,
                slTraCham_CE_ICT_30p: [...deptEmployees].sort((a, b) => a.slTraCham_CE_ICT - b.slTraCham_CE_ICT)[Math.floor(count * 0.3)]?.slTraCham_CE_ICT,
            };
        }
    }

    const finalFullSellerArray = initialEmployeeData.fullSellerArray.map(emp => {
        const thresholds = deptThresholds[emp.department];
        let weakPointsRevenue = 0;
        let weakPointsExploitation = 0;

        if (thresholds) {
            if (emp.doanhThuQD <= thresholds.dtqd_40p) weakPointsRevenue++;
            if (emp.hieuQuaValue < 35) weakPointsRevenue++;
            if (emp.dtTraChamPercent_CE_ICT < 45) weakPointsRevenue++;

            if (emp.slCE_ICT <= thresholds.slCE_ICT_30p) weakPointsExploitation++;
            if (emp.slTraCham_CE_ICT <= thresholds.slTraCham_CE_ICT_30p) weakPointsExploitation++;
            if (emp.traChamPercent_CE_ICT < 50) weakPointsExploitation++;
        }

        return { ...emp, weakPointsRevenue, weakPointsExploitation };
    });

    return { ...initialEmployeeData, fullSellerArray: finalFullSellerArray };
}

import type { DataRow, ProductConfig, Status } from '../types';
import { getRowValue, parseExcelDate } from '../utils/dataUtils';
import { COL } from '../constants';
import * as XLSX from 'xlsx';

type StatusUpdater = (status: Status) => void;

export type DepartmentMap = { [employeeId: string]: string };

function robustCsvParse(text: string): string[][] {
    const lines = text.split(/\r?\n/);
    const result: string[][] = [];

    for (const line of lines) {
        if (!line.trim()) continue;

        const row: string[] = [];
        let cell = '';
        let inQuotes = false;

        for (let i = 0; i < line.length; i++) {
            const char = line[i];

            if (char === '"') {
                if (inQuotes && i + 1 < line.length && line[i + 1] === '"') {
                    // Handle escaped quote ""
                    cell += '"';
                    i++; // Skip next quote
                } else {
                    inQuotes = !inQuotes;
                }
            } else if (char === ',' && !inQuotes) {
                row.push(cell.trim());
                cell = '';
            } else {
                cell += char;
            }
        }
        row.push(cell.trim());
        result.push(row);
    }
    return result;
}


export async function loadConfigFromSheet(url: string, setStatus: StatusUpdater): Promise<ProductConfig> {
    setStatus({ message: 'Đang tải file cấu hình...', type: 'info', progress: 0 });
    try {
        const response = await fetch(url);
        if (!response.ok) {
            throw new Error(`Không thể tải file cấu hình. Status: ${response.status}`);
        }
        const csvText = await response.text();
        setStatus({ message: 'Đang xử lý file cấu hình...', type: 'info', progress: 50 });

        const parsedRows = robustCsvParse(csvText);

        if (parsedRows.length < 2) {
             throw new Error('File cấu hình không hợp lệ hoặc không có dữ liệu.');
        }

        const headers = parsedRows[0].map(h => h.trim());
        const data = parsedRows.slice(1);

        const config: ProductConfig = {
            groups: {},
            subgroups: {},
            childToParentMap: {},
            childToSubgroupMap: {}
        };

        const groupIndex = headers.indexOf('NhomCha');
        const subgroupIndex = headers.indexOf('NhomCon');
        const productCodeIndex = headers.indexOf('NhomHang');

        if (groupIndex === -1 || subgroupIndex === -1 || productCodeIndex === -1) {
            console.error('Headers found:', headers);
            throw new Error('File cấu hình thiếu các cột bắt buộc: NhomCha, NhomCon, NhomHang');
        }

        data.forEach(row => {
            if (row.length > Math.max(groupIndex, subgroupIndex, productCodeIndex)) {
                const parentGroup = row[groupIndex];
                const childGroup = row[subgroupIndex];
                const productCode = row[productCodeIndex];

                if (parentGroup && childGroup && productCode) {
                    if (!config.groups[parentGroup]) {
                        config.groups[parentGroup] = new Set();
                    }
                    config.groups[parentGroup].add(productCode);

                    if (!config.subgroups[parentGroup]) {
                        config.subgroups[parentGroup] = {};
                    }
                    if (!config.subgroups[parentGroup][childGroup]) {
                        config.subgroups[parentGroup][childGroup] = [];
                    }
                    config.subgroups[parentGroup][childGroup].push(productCode);

                    config.childToParentMap[productCode] = parentGroup;
                    config.childToSubgroupMap[productCode] = childGroup;
                }
            }
        });

        if (Object.keys(config.groups).length === 0) {
            throw new Error("Không thể xử lý dữ liệu từ file cấu hình. Vui lòng kiểm tra định dạng.");
        }

        setStatus({ message: 'Tải cấu hình thành công.', type: 'success', progress: 100 });
        return config;
    } catch (error) {
        console.error("Lỗi khi tải cấu hình:", error);
        const errorMessage = error instanceof Error ? error.message : "Lỗi không xác định khi tải cấu hình";
        setStatus({ message: errorMessage, type: 'error', progress: 0 });
        throw error;
    }
}

export async function processShiftFile(file: File): Promise<{ map: DepartmentMap, uniqueDepartments: string[] }> {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = (e: ProgressEvent<FileReader>) => {
            try {
                if (!e.target?.result) throw new Error("Không thể đọc file phân ca.");

                const data = new Uint8Array(e.target.result as ArrayBuffer);
                const workbook = XLSX.read(data, { type: 'array' });
                const sheetName = workbook.SheetNames[0];
                const worksheet = workbook.Sheets[sheetName];
                const rows: any[][] = XLSX.utils.sheet_to_json(worksheet, { header: 1, defval: null });

                const map: DepartmentMap = {};
                let currentDepartment: string | null = null;
                const departments = new Set<string>();

                for (let i = 1; i < rows.length; i++) {
                    const row = rows[i];
                    if (row[0] && typeof row[0] === 'string' && row[0].trim() !== '') {
                        currentDepartment = row[0].trim();
                    }

                    const userId = row[1];

                    if (userId && currentDepartment) {
                        const userIdStr = String(userId).trim();
                        const cleanId = userIdStr.split(' - ')[0].trim();
                        if (cleanId) {
                             map[cleanId] = currentDepartment;
                             departments.add(currentDepartment);
                        }
                    }
                }

                if (Object.keys(map).length === 0) {
                    throw new Error("File phân ca không hợp lệ hoặc không chứa dữ liệu nhân viên và bộ phận.");
                }

                resolve({ map, uniqueDepartments: Array.from(departments).sort() });

            } catch (error) {
                console.error("Lỗi khi xử lý file phân ca:", error);
                const errorMessage = error instanceof Error ? error.message : "Lỗi không xác định khi xử lý file phân ca";
                reject(new Error(errorMessage));
            }
        };
        reader.onerror = (error) => reject(error);
        reader.readAsArrayBuffer(file);
    });
}

/**
 * Xử lý file YCX trực tiếp trên Main Thread (Tốc độ cao cho file < 50MB)
 * Thay thế Worker để tránh overhead load thư viện.
 */
export async function processSalesFile(file: File, enableDeduplication: boolean, setStatus: StatusUpdater): Promise<DataRow[]> {
    setStatus({ message: 'Đang đọc file...', type: 'info', progress: 10 });

    try {
        const arrayBuffer = await file.arrayBuffer();

        setStatus({ message: 'Đang phân tích Excel...', type: 'info', progress: 30 });
        const data = new Uint8Array(arrayBuffer);
        // Use dense mode for memory efficiency
        const workbook = XLSX.read(data, { type: 'array', cellDates: true, dense: true });

        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];

        setStatus({ message: 'Đang chuyển đổi dữ liệu...', type: 'info', progress: 50 });
        const json: DataRow[] = XLSX.utils.sheet_to_json(worksheet, { defval: '' });

        let processedList: DataRow[] = json;

        if (enableDeduplication) {
            setStatus({ message: 'Đang xóa dữ liệu trùng...', type: 'info', progress: 70 });
            const uniqueSet = new Set<string>();
            const deduplicated: DataRow[] = [];

            const len = json.length;
            for (let i = 0; i < len; i++) {
                const row = json[i];
                let signature = '';
                // Fast signature generation
                for (const key in row) {
                    if (key !== 'STT_1') {
                        signature += row[key] + '§'; 
                    }
                }

                if (!uniqueSet.has(signature)) {
                    uniqueSet.add(signature);
                    deduplicated.push(row);
                }
            }
            processedList = deduplicated;
            uniqueSet.clear(); 
        }

        setStatus({ message: 'Đang chuẩn hóa dữ liệu...', type: 'info', progress: 90 });

        const validResults: DataRow[] = [];
        const len = processedList.length;

        for (let i = 0; i < len; i++) {
            const row = processedList[i];

            // Inline validation logic
            const trangThaiHuy = (getRowValue(row, COL.TRANG_THAI_HUY) || '').toString();
            if (trangThaiHuy.length !== 8 && trangThaiHuy.toLowerCase().trim() !== 'chưa hủy') continue;

            const nhapTra = (getRowValue(row, COL.TINH_TRANG_NHAP_TRA) || '').toString();
            if (nhapTra.length !== 8 && nhapTra.toLowerCase().trim() !== 'chưa trả') continue;

            const thuTien = (getRowValue(row, COL.TRANG_THAI_THU_TIEN) || '').toString();
            if (thuTien.length !== 6 && thuTien.toLowerCase().trim() !== 'đã thu') continue;

            // Normalize Date
            const parsedDate = parseExcelDate(getRowValue(row, COL.DATE_CREATED));
            if (parsedDate && !isNaN(parsedDate.getTime())) {
                row.parsedDate = parsedDate;
                validResults.push(row);
            }
        }

        if (validResults.length === 0) {
            throw new Error("Không tìm thấy dữ liệu hợp lệ (Chưa hủy, Chưa trả, Đã thu) hoặc lỗi ngày tháng.");
        }

        setStatus({ message: 'Hoàn tất xử lý.', type: 'success', progress: 100 });
        return validResults;

    } catch (error) {
        console.error("Lỗi xử lý file:", error);
        throw error;
    }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
