import * as XLSX from 'xlsx';
import type { ProductConfig } from '../types';

export type DepartmentMap = { [key: string]: string };

export async function loadConfigFromSheet(url: string, onProgress: (msg: string) => void): Promise<ProductConfig> {
    onProgress('Đang tải cấu hình sản phẩm...');
    try {
        const response = await fetch(url);
        const csvText = await response.text();
        const lines = csvText.split('\n');

        const groups: { [key: string]: Set<string> } = {};
        const subgroups: { [key: string]: { [key: string]: string[] } } = {};
        const childToParentMap: { [key: string]: string } = {};
        const childToSubgroupMap: { [key: string]: string } = {};

        // Skip header
        for (let i = 1; i < lines.length; i++) {
            const line = lines[i].trim();
            if (!line) continue;

            // Expected CSV format: NhomCha, NhomCon, MaNhomHang, ...
            const parts = line.split(','); // Simple CSV split
            if (parts.length < 3) continue;

            const parent = parts[0].trim();
            const child = parts[1].trim();
            const code = parts[2].trim();

            if (!groups[parent]) groups[parent] = new Set();
            groups[parent].add(child);

            if (!subgroups[parent]) subgroups[parent] = {};
            if (!subgroups[parent][child]) subgroups[parent][child] = [];
            subgroups[parent][child].push(code);

            childToParentMap[code] = parent;
            childToSubgroupMap[code] = child;
        }

        return { groups, subgroups, childToParentMap, childToSubgroupMap };
    } catch (error) {
        console.error("Error loading config:", error);
        return { groups: {}, subgroups: {}, childToParentMap: {}, childToSubgroupMap: {} };
    }
}

export async function processShiftFile(file: File): Promise<{ map: DepartmentMap }> {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const data = new Uint8Array(e.target?.result as ArrayBuffer);
                const workbook = XLSX.read(data, { type: 'array' });
                const firstSheetName = workbook.SheetNames[0];
                const worksheet = workbook.Sheets[firstSheetName];
                const jsonData = XLSX.utils.sheet_to_json(worksheet, { header: 1 }) as any[][];

                const map: DepartmentMap = {};
                let currentDepartment = '';

                for (let i = 0; i < jsonData.length; i++) {
                    const row = jsonData[i];
                    if (row.length === 0) continue;

                    const firstCell = (row[0] || '').toString().trim();
                    if (firstCell.toLowerCase().startsWith('bộ phận') || (firstCell && !row[1])) {
                         currentDepartment = firstCell.replace(/^Bộ phận\s*[:|-]?\s*/i, '').trim();
                         continue;
                    }

                    const secondCell = (row[1] || '').toString().trim();
                    if (secondCell && currentDepartment) {
                        const cleanId = secondCell.split(' - ')[0].trim();
                        // Validate ID is numeric
                        if (cleanId && /^\d+$/.test(cleanId)) {
                             map[cleanId] = `${currentDepartment}|${secondCell}`;
                        }
                    }
                }

                resolve({ map });
            } catch (error) {
                reject(error);
            }
        };
        reader.onerror = (error) => reject(error);
        reader.readAsArrayBuffer(file);
    });
}

import type { DataRow, FilterState, ProcessedData, ProductConfig } from '../types';
import { DepartmentMap } from './dataService';
import { COL } from '../constants';
import { getRowValue } from '../utils/dataUtils';
import { processKpis } from './kpiService';
import { processTrendData } from './trendService';
import { processIndustryData } from './industryService';
import { processSummaryTable, calculateWarehouseSummary } from './summaryService';
import { processEmployeeData } from './employeeService';

export function applyFiltersAndProcess(
    originalData: DataRow[],
    productConfig: ProductConfig,
    filters: FilterState,
    departmentMap: DepartmentMap | null
): { processedData: ProcessedData; baseFilteredData: DataRow[] } {

    // 1. Filter Data
    const baseFilteredData = originalData.filter(row => {
        // Kho
        if (filters.kho !== 'all') {
            const kho = getRowValue(row, COL.KHO);
            if (kho !== filters.kho) return false;
        }

        // Xuat
        if (filters.xuat !== 'all') {
            const xuatValue = getRowValue(row, COL.XUAT) || '';
            const xuatStatus = xuatValue.toLowerCase().includes('đã') ? 'Đã' : 'Chưa';
            if (xuatStatus !== filters.xuat) return false;
        }

        // Trang Thai
        if (filters.trangThai.length > 0) {
            const trangThai = getRowValue(row, COL.TRANG_THAI);
            if (!filters.trangThai.includes(trangThai)) return false;
        }

        // Nguoi Tao
        if (filters.nguoiTao.length > 0) {
            const nguoiTao = getRowValue(row, COL.NGUOI_TAO);
            if (!filters.nguoiTao.includes(nguoiTao)) return false;
        }

        // Department
        if (departmentMap && filters.department && filters.department.length > 0) {
            const creator = getRowValue(row, COL.NGUOI_TAO);
            if (!creator) return false;

            const creatorId = creator.split(' - ')[0].trim();
            const deptVal = departmentMap[creatorId];
            const department = deptVal ? deptVal.split('|')[0] : undefined;

            if (!department || !filters.department.includes(department)) {
                return false;
            }
        }

        // Date Range
        const rowDate = row.parsedDate;
        if (!rowDate) return false;

        if (filters.startDate) {
            const start = new Date(filters.startDate);
            start.setHours(0, 0, 0, 0);
            if (rowDate < start) return false;
        }

        if (filters.endDate) {
            const end = new Date(filters.endDate);
            end.setHours(23, 59, 59, 999);
            if (rowDate > end) return false;
        }

        return true;
    });

    // 2. Process specific subsets
    const validSalesData = baseFilteredData.filter(row => {
        const trangThaiHuy = (getRowValue(row, COL.TRANG_THAI_HUY) || '').toString().toLowerCase();
        const nhapTra = (getRowValue(row, COL.TINH_TRANG_NHAP_TRA) || '').toString().toLowerCase();
        const thuTien = (getRowValue(row, COL.TRANG_THAI_THU_TIEN) || '').toString().toLowerCase();
        return trangThaiHuy === 'chưa hủy' && nhapTra === 'chưa trả' && thuTien === 'đã thu';
    });

    const unshippedOrders = validSalesData.filter(row => {
        const xuat = (getRowValue(row, COL.XUAT) || '').toString().toLowerCase();
        return xuat.includes('chưa');
    });

    // 3. Aggregate Data
    const kpis = processKpis(validSalesData, unshippedOrders, baseFilteredData, productConfig);
    const trendData = processTrendData(validSalesData, productConfig);
    const industryData = processIndustryData(validSalesData, productConfig, filters);
    const summaryTable = processSummaryTable(validSalesData, productConfig, filters);
    const employeeData = processEmployeeData(validSalesData, productConfig, departmentMap);
    const warehouseSummary = calculateWarehouseSummary(originalData, filters, productConfig);

    const lastUpdated = new Date().toLocaleString('vi-VN');
    const reportSubTitle = filters.dateRange === 'all' ? 'Toàn bộ thời gian' : `${filters.startDate} - ${filters.endDate}`;

    return {
        processedData: {
            kpis,
            trendData,
            industryData,
            employeeData,
            summaryTable,
            unshippedOrders,
            filteredValidSalesData: validSalesData,
            lastUpdated,
            reportSubTitle,
            warehouseSummary
        },
        baseFilteredData
    };
}

