        const revenue = price;
        const revenueQD = revenue * heso;
        const hinhThuc = getHinhThucThanhToan(row);

        // Core Stats
        emp.doanhThuThuc += revenue;
        emp.doanhThuQD += revenueQD;
        exp.doanhThuThuc += revenue;
        exp.doanhThuQD += revenueQD;

        if (hinhThuc === 'tra_gop') {
            emp.doanhThuTraCham += revenue;
            emp.slTraCham++; 
        }
        if (hinhThuc === 'thu_ho') {
            emp.slThuHo++;
        }

        const orderId = getRowValue(row, COL.ID);
        if (orderId && !processedOrders.has(`${creator}-${orderId}`)) {
            processedOrders.add(`${creator}-${orderId}`);
            emp.totalOrders++;
        }

        const customerName = getRowValue(row, COL.CUSTOMER_NAME);
        if (customerName) {
             emp.slTiepCan++; 
        }

        // Categorization for Exploitation
        const parentGroup = productConfig.childToParentMap[maNhomHang];
        const childGroup = productConfig.childToSubgroupMap[maNhomHang];

        const isICT = parentGroup === 'ICT' || parentGroup === 'Laptop' || parentGroup === 'Tablet';
        const isCE = parentGroup === 'CE' || parentGroup === 'Tivi' || parentGroup === 'Tủ lạnh'; 
        const isGiaDungMain = parentGroup === 'Gia dụng';

        if (isICT) { exp.slICT += quantity; exp.doanhThuICT += revenue; emp.slCE_ICT += quantity; emp.doanhThu_CE_ICT += revenue; if(hinhThuc==='tra_gop') { emp.slTraCham_CE_ICT += quantity; emp.doanhThuTraCham_CE_ICT += revenue; } }
        if (isCE) { exp.slCE_main += quantity; exp.doanhThuCE_main += revenue; emp.slCE_ICT += quantity; emp.doanhThu_CE_ICT += revenue; if(hinhThuc==='tra_gop') { emp.slTraCham_CE_ICT += quantity; emp.doanhThuTraCham_CE_ICT += revenue; } }
        if (isGiaDungMain) { exp.slGiaDung_main += quantity; } 

        if (parentGroup === 'Bảo hiểm') { exp.slBaoHiem += quantity; exp.doanhThuBaoHiem += revenue; }
        if (parentGroup === 'Sim') { exp.slSim += quantity; exp.doanhThuSim += revenue; }
        if (parentGroup === 'Wearable' || parentGroup === 'Đồng hồ') { exp.slDongHo += quantity; exp.doanhThuDongHo += revenue; }
        if (parentGroup === 'Phụ kiện') { exp.doanhThuPhuKien += revenue; exp.slPhuKien += quantity; }
        if (parentGroup === 'Gia dụng') { exp.doanhThuGiaDung += revenue; exp.slGiaDung += quantity; }

        if (childGroup === 'Camera') exp.slCamera += quantity;
        if (childGroup === 'Loa') exp.slLoa += quantity;
        if (childGroup === 'Sạc dự phòng' || childGroup === 'Pin sạc dự phòng') exp.slPinSDP += quantity;
        if (childGroup === 'Tai nghe') exp.slTaiNgheBLT += quantity;
        if (childGroup === 'Máy lọc nước') exp.slMayLocNuoc += quantity;
        if (childGroup === 'Nồi cơm điện') exp.slNoiCom += quantity;
        if (childGroup === 'Nồi chiên không dầu') exp.slNoiChien += quantity;
        if (childGroup === 'Quạt') exp.slQuatDien += quantity;

    });

    // Post-processing
    Object.values(employeeStats).forEach(emp => {
        emp.hieuQuaValue = emp.doanhThuThuc > 0 ? ((emp.doanhThuQD - emp.doanhThuThuc) / emp.doanhThuThuc) * 100 : 0;
        emp.traChamPercent = emp.totalOrders > 0 ? (emp.slTraCham / emp.totalOrders) * 100 : 0;
        emp.aov = emp.totalOrders > 0 ? emp.doanhThuThuc / emp.totalOrders : 0;

        emp.traChamPercent_CE_ICT = emp.slCE_ICT > 0 ? (emp.slTraCham_CE_ICT / emp.slCE_ICT) * 100 : 0;
        emp.dtTraChamPercent_CE_ICT = emp.doanhThu_CE_ICT > 0 ? (emp.doanhThuTraCham_CE_ICT / emp.doanhThu_CE_ICT) * 100 : 0;
    });

    Object.values(exploitationStats).forEach(exp => {
        exp.hieuQuaQD = exp.doanhThuThuc > 0 ? ((exp.doanhThuQD - exp.doanhThuThuc) / exp.doanhThuThuc) * 100 : 0;
        const totalMain = exp.slICT + exp.slCE_main + exp.slGiaDung_main;
        exp.percentBaoHiem = totalMain > 0 ? (exp.slBaoHiem / totalMain) * 100 : 0;
    });

    const fullSellerArray = Object.values(employeeStats);
    const exploitationData = Object.values(exploitationStats);

    const averages = {
        doanhThuThuc: fullSellerArray.length ? fullSellerArray.reduce((s, e) => s + e.doanhThuThuc, 0) / fullSellerArray.length : 0,
        doanhThuQD: fullSellerArray.length ? fullSellerArray.reduce((s, e) => s + e.doanhThuQD, 0) / fullSellerArray.length : 0,
        hieuQuaValue: fullSellerArray.length ? fullSellerArray.reduce((s, e) => s + e.hieuQuaValue, 0) / fullSellerArray.length : 0
    };

    const maxValues = {
        doanhThuThuc: Math.max(...fullSellerArray.map(e => e.doanhThuThuc), 0),
        doanhThuQD: Math.max(...fullSellerArray.map(e => e.doanhThuQD), 0)
    };

    return {
        fullSellerArray,
        exploitationData,
        averages,
        maxValues,
        byIndustry: employeeIndustryStats,
        dailyTrend: employeeDailyTrend
    };
}

import React, { useState, useMemo, useRef } from 'react';
import type { Employee, EmployeeData } from '../../types';
import { formatCurrency, formatQuantity, abbreviateName } from '../../utils/dataUtils';
import { Icon } from '../common/Icon';
import { exportElementAsImage } from '../../services/uiService';

export type SortKey = keyof Employee | 'custom_index';

interface PerformanceTableProps {
    employeeData: EmployeeData;
    onEmployeeClick: (name: string) => void;
    onExport: () => void;
    isExporting?: boolean;
}

const PerformanceTable: React.FC<PerformanceTableProps> = ({ employeeData, onEmployeeClick, onExport, isExporting }) => {
    const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({ key: 'doanhThuQD', direction: 'desc' });
    const [groupType, setGroupType] = useState<'all' | 'vuotTroi' | 'canCaiThien'>('all');
    const tableRef = useRef<HTMLDivElement>(null);

    const onSort = (key: SortKey) => {
        setSortConfig(current => ({
            key,
            direction: current.key === key && current.direction === 'desc' ? 'asc' : 'desc'
        }));
    };

    const sortedData = useMemo(() => {
        let data = [...employeeData.fullSellerArray];

        if (groupType === 'vuotTroi') {
            data = data.filter(e => e.hieuQuaValue >= 40 && e.doanhThuQD > employeeData.averages.doanhThuQD);
        } else if (groupType === 'canCaiThien') {
            data = data.filter(e => e.hieuQuaValue < 35 || e.doanhThuQD < employeeData.averages.doanhThuQD);
        }

        return data.sort((a, b) => {
            const valA = a[sortConfig.key as keyof Employee] || 0;
            const valB = b[sortConfig.key as keyof Employee] || 0;
            if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
            if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
            return 0;
        });
    }, [employeeData, sortConfig, groupType]);

    const renderHeader = (label: string, sortKey: SortKey) => {
        return (
            <th 
                onClick={() => onSort(sortKey)}
                className={`px-3 py-3 text-xs font-bold uppercase tracking-wider cursor-pointer text-center text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors select-none whitespace-nowrap`}
            >
                <div className="flex items-center justify-center gap-1">
                    {label}
                    {sortConfig.key === sortKey && <Icon name={sortConfig.direction === 'asc' ? 'arrow-up' : 'arrow-down'} size={3} />}
                </div>
            </th>
        );
    };

    return (
        <div ref={tableRef} className="overflow-hidden">
            <div className="flex justify-between items-center mb-4 hide-on-export">
                <div className="flex gap-2">
                    <button onClick={() => setGroupType('all')} className={`px-3 py-1.5 rounded-lg text-sm font-semibold transition-colors ${groupType === 'all' ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200 dark:bg-slate-800 dark:text-slate-300'}`}>Tất cả</button>
                    <button onClick={() => setGroupType('vuotTroi')} className={`px-3 py-1.5 rounded-lg text-sm font-semibold transition-colors ${groupType === 'vuotTroi' ? 'bg-green-600 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200 dark:bg-slate-800 dark:text-slate-300'}`}>Vượt trội</button>
                    <button onClick={() => setGroupType('canCaiThien')} className={`px-3 py-1.5 rounded-lg text-sm font-semibold transition-colors ${groupType === 'canCaiThien' ? 'bg-red-600 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200 dark:bg-slate-800 dark:text-slate-300'}`}>Cần cải thiện</button>
                </div>
                <button onClick={onExport} disabled={isExporting} className="p-2 text-slate-500 hover:text-indigo-600 transition-colors">
                    {isExporting ? <Icon name="loader-2" className="animate-spin"/> : <Icon name="camera"/>}
                </button>
            </div>

            <div className="overflow-x-auto rounded-lg border border-slate-200 dark:border-slate-700">
                <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                    <thead className="bg-slate-50 dark:bg-slate-800">
                        <tr>
                            {renderHeader('Nhân Viên', 'name')}
                            {renderHeader('Bộ Phận', 'department')}
                            {renderHeader('Doanh Thu', 'doanhThuThuc')}
                            {renderHeader('DT Quy Đổi', 'doanhThuQD')}
                            {renderHeader('Hiệu Quả', 'hieuQuaValue')}
                            {renderHeader('ĐH Trả Góp', 'slTraCham')}
                            {renderHeader('Tiếp Cận', 'slTiepCan')}
                        </tr>
                    </thead>
                    <tbody className="bg-white dark:bg-slate-900 divide-y divide-slate-200 dark:divide-slate-700">
                        {sortedData.map((emp) => (
                            <tr key={emp.name} onClick={() => onEmployeeClick(emp.name)} className="hover:bg-slate-50 dark:hover:bg-slate-800 cursor-pointer transition-colors">
                                <td className="px-3 py-3 text-sm font-medium text-slate-900 dark:text-slate-100 whitespace-nowrap">{abbreviateName(emp.name)}</td>
                                <td className="px-3 py-3 text-sm text-slate-500 dark:text-slate-400 whitespace-nowrap">{emp.department}</td>
                                <td className="px-3 py-3 text-sm text-right text-slate-600 dark:text-slate-300">{formatCurrency(emp.doanhThuThuc)}</td>
                                <td className="px-3 py-3 text-sm text-right font-bold text-indigo-600 dark:text-indigo-400">{formatCurrency(emp.doanhThuQD)}</td>
                                <td className={`px-3 py-3 text-sm text-center font-semibold ${emp.hieuQuaValue >= 40 ? 'text-green-600' : 'text-red-500'}`}>{emp.hieuQuaValue.toFixed(0)}%</td>
                                <td className="px-3 py-3 text-sm text-center text-slate-600 dark:text-slate-300">{emp.slTraCham}</td>
                                <td className="px-3 py-3 text-sm text-center text-slate-600 dark:text-slate-300">{formatQuantity(emp.slTiepCan)}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default PerformanceTable;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import type { AppState, Status, ProcessedData, DataRow, FilterState, ProductConfig, ChatMessage, Employee } from '../types';
import type { Chat } from '@google/genai';
import { loadConfigFromSheet, processShiftFile, DepartmentMap } from '../services/dataService';
import { applyFiltersAndProcess } from '../services/filterService';
import { exportElementAsImage } from '../services/uiService';
import { createChatSession } from '../services/aiService';
import { saveDepartmentMap, getDepartmentMap, clearDepartmentMap, saveSalesData, getSalesData, clearSalesData, getProductConfig, saveProductConfig, clearProductConfig, clearCustomTabs } from '../services/dbService';
import { getRowValue } from '../utils/dataUtils';
import { COL } from '../constants';

const initialFilterState: FilterState = {
    kho: 'all',
    xuat: 'all',
    trangThai: [],
    nguoiTao: [],
    department: [],
    startDate: '',
    endDate: '',
    dateRange: 'all',
    industryGrid: {
        selectedGroups: [],
        selectedSubgroups: [],
    },
    summaryTable: {
        parent: [],
        child: [],
        manufacturer: [],
        creator: [],
        product: [],
        drilldownOrder: ['manufacturer', 'creator'],
        sort: { column: 'totalRevenue', direction: 'desc' }
    }
};

export const useDashboardLogic = () => {
    const [status, setStatus] = useState<Status>({ message: '', type: 'info', progress: 0 });
    const [appState, setAppState] = useState<AppState>('loading');
    const [isProcessing, setIsProcessing] = useState(false);
    const [isClearingDepartments, setIsClearingDepartments] = useState(false);
    const [isExporting, setIsExporting] = useState(false);
    const [fileInfo, setFileInfo] = useState<{ filename: string; savedAt: string } | null>(null);

    const [originalData, setOriginalData] = useState<DataRow[]>([]);
    const [baseFilteredData, setBaseFilteredData] = useState<DataRow[]>([]);
    const [productConfig, setProductConfig] = useState<ProductConfig | null>(null);
    const [departmentMap, setDepartmentMap] = useState<DepartmentMap | null>(null);
    const [processedData, setProcessedData] = useState<ProcessedData | null>(null);
    const [employeeAnalysisData, setEmployeeAnalysisData] = useState<ProcessedData['employeeData'] | null>(null);
    const [configUrl, setConfigUrl] = useState('https://docs.google.com/spreadsheets/d/e/2PACX-1vRhes_lcas8n2_xYHKylsjyD3PIVbdchCiL2XDKJ4OYfgUZlVjAT7ZGWDHrYRzQVrK2w50W86Da3l48/pub?output=csv');

    const [filterState, setFilterState] = useState<FilterState>(() => {
        try {
            const saved = localStorage.getItem('industryGridFilters');
            const industryGrid = saved ? JSON.parse(saved) : initialFilterState.industryGrid;
            if (!industryGrid.selectedSubgroups) {
                industryGrid.selectedSubgroups = [];
            }
            return { ...initialFilterState, industryGrid };
        } catch (e) {
            return initialFilterState;
        }
    });
    const [uniqueFilterOptions, setUniqueFilterOptions] = useState<{ kho: string[]; trangThai: string[]; nguoiTao: string[], department: string[] }>({ kho: [], trangThai: [], nguoiTao: [], department: [] });

    const [activeModal, setActiveModal] = useState<'performance' | 'unshipped' | null>(null);
    const [modalData, setModalData] = useState<any>(null);

    const [isChatOpen, setIsChatOpen] = useState(false);
    const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
    const [isAiResponding, setIsAiResponding] = useState(false);
    const chatSession = useRef<Chat | null>(null);
    const [processingTime, setProcessingTime] = useState(0);

    // Filter Options Setup Effect
    useEffect(() => {
        if (originalData.length > 0) {
            const khoOptions = [...new Set(originalData.map(r => getRowValue(r, COL.KHO)).filter(Boolean).map(String))];
            const trangThaiOptions = [...new Set(originalData.map(r => getRowValue(r, COL.TRANG_THAI)).filter(Boolean).map(String))];
            const nguoiTaoOptions = [...new Set(originalData.map(r => getRowValue(r, COL.NGUOI_TAO)).filter(Boolean).map(String))];

            let deptOptions: string[] = [];
            if(departmentMap) {
                // Tách lấy tên bộ phận từ value (format: "Dept|Name")
                const uniqueDepartments = Array.from(new Set(Object.values(departmentMap).map(val => val.split('|')[0]))).sort();
                const excludedKeywords = ['quản lý', 'trưởng ca', 'kế toán', 'tiếp đón khách hàng'];
                deptOptions = uniqueDepartments.filter(d => !excludedKeywords.some(keyword => d.toLowerCase().includes(keyword)));
            }

            setUniqueFilterOptions({ kho: khoOptions, trangThai: trangThaiOptions, nguoiTao: nguoiTaoOptions, department: deptOptions });
        }
    }, [originalData, departmentMap]);

    // Initial Data Loading Effect
    useEffect(() => {
        const loadInitialData = async () => {
            setAppState('loading');
            setIsProcessing(true);
            try {
                let config: ProductConfig;
                const cachedConfig = await getProductConfig();
                if (cachedConfig) {
                    config = cachedConfig.config;
                } else {
                    config = await loadConfigFromSheet(configUrl, () => {});
                    await saveProductConfig(config, configUrl);
                }
                setProductConfig(config);

                const savedDeptMap = await getDepartmentMap();
                if (savedDeptMap) setDepartmentMap(savedDeptMap);

                const savedSales = await getSalesData();
                if (savedSales && savedSales.data.length > 0) {
                    setStatus({ message: 'Đang tải dữ liệu đã lưu...', type: 'info', progress: 25 });
                    setFileInfo({ filename: savedSales.filename, savedAt: savedSales.savedAt.toLocaleString('vi-VN') });

                    const rehydratedData = savedSales.data.map(row => ({
                        ...row,
                        parsedDate: row.parsedDate ? new Date(row.parsedDate as string) : null,
                    })).filter(row => row.parsedDate && !isNaN(row.parsedDate.getTime()));

                    setOriginalData(rehydratedData);
                    setAppState('dashboard');
                    setIsProcessing(true);
                } else {
                    setAppState('upload');
                    setIsProcessing(false);
                }
            } catch (e) {
                console.error("Lỗi khi tải dữ liệu ban đầu:", e);
                const msg = e instanceof Error ? e.message : 'Lỗi không xác định khi tải dữ liệu.';
                setStatus({ message: msg, type: 'error', progress: 0 });
                setAppState('upload');
                await Promise.all([clearSalesData(), clearDepartmentMap(), clearProductConfig()]);
                setIsProcessing(false);
            }
        };
        loadInitialData();
    }, [configUrl]);

    const handleFilterChange = useCallback((newFilters: Partial<FilterState>) => {
        setFilterState(prev => {
            const updated = { ...prev, ...newFilters };
            if (newFilters.industryGrid) {
                updated.industryGrid = { ...prev.industryGrid, ...newFilters.industryGrid };
                localStorage.setItem('industryGridFilters', JSON.stringify(updated.industryGrid));
            }
            if (newFilters.summaryTable) {
                updated.summaryTable = { ...prev.summaryTable, ...newFilters.summaryTable };
            }
            return updated;
        });
    }, []);

    // Logic for applyFiltersAndProcess is imported, so just call it
    useEffect(() => {
        if (appState !== 'dashboard' || !originalData.length || !productConfig) return;

        setIsProcessing(true);
        const startTime = Date.now();

        const timer = setTimeout(() => {
            try {
                const { processedData: result, baseFilteredData: newBaseData } = applyFiltersAndProcess(originalData, productConfig, filterState, departmentMap);
                setProcessedData(result);
                setBaseFilteredData(newBaseData);

                if (departmentMap) {
                    const employeeFilterState = { ...filterState, department: [] };
                    const { processedData: employeeResult } = applyFiltersAndProcess(originalData, productConfig, employeeFilterState, departmentMap);
                    setEmployeeAnalysisData(employeeResult.employeeData);
                } else {
                    setEmployeeAnalysisData(result.employeeData);
                }
                setProcessingTime(Date.now() - startTime);
            } catch (error) {
                console.error("Lỗi khi xử lý lại dữ liệu:", error);
                setStatus({ message: "Đã xảy ra lỗi trong quá trình xử lý dữ liệu.", type: 'error', progress: 0 });
                setAppState('upload');
            } finally {
                setIsProcessing(false);
            }
        }, 100);

        return () => clearTimeout(timer);
    }, [appState, originalData, productConfig, filterState, departmentMap]);

    // Use Worker for file processing
    const handleFileProcessing = async (file: File) => {
        if (!window.Worker) {
            setStatus({ message: 'Trình duyệt không hỗ trợ Web Worker.', type: 'error', progress: 0 });
            return;
        }
        setAppState('loading');
        setIsProcessing(true);
        setStatus({ message: 'Đang khởi tạo worker...', type: 'info', progress: 0 });

        const worker = new Worker(new URL('../services/worker.ts', import.meta.url), { type: 'module' });

        worker.onmessage = async (e) => {
            const { type, payload } = e.data;
            if (type === 'progress') {
                setStatus(payload);
            } else if (type === 'result') {
                await saveSalesData(payload, file.name);
                setFileInfo({ filename: file.name, savedAt: new Date().toLocaleString('vi-VN') });
                setOriginalData(payload);
                setAppState('dashboard');
                worker.terminate();
            } else if (type === 'error') {
                setStatus({ message: payload, type: 'error', progress: 0 });
                setAppState('upload');
                setIsProcessing(false);
                worker.terminate();
            }
        };

        worker.postMessage({ file, enableDeduplication: true });
    };

    const handleShiftFileProcessing = async (files: File[]) => {
        if (files.length === 0) return;
        setAppState('loading');
        setIsProcessing(true);
        setStatus({ message: `Đang xử lý ${files.length} file phân ca...`, type: 'info', progress: 0 });
        try {
            let mergedMap: DepartmentMap = (await getDepartmentMap()) || {};

            for (let i = 0; i < files.length; i++) {
                const file = files[i];
                setStatus({ message: `Đang xử lý file ${i + 1}/${files.length}: ${file.name}`, type: 'info', progress: 20 + (60 * (i + 1) / files.length) });
                const { map } = await processShiftFile(file); 
                mergedMap = { ...mergedMap, ...map };
            }

            await saveDepartmentMap(mergedMap);
            setDepartmentMap(mergedMap);
            setStatus({ message: `Đã xử lý và gộp ${files.length} file phân ca!`, type: 'success', progress: 100 });
        } catch (error) {
            const msg = error instanceof Error ? error.message : "Lỗi không xác định";
            setStatus({ message: msg, type: 'error', progress: 0 });
        } finally {
            setIsProcessing(false);
            if(originalData.length > 0) setAppState('dashboard');
            else setAppState('upload');
        }
    };

    const handleClearDepartments = async () => {
        setIsClearingDepartments(true);
        try {
            await clearDepartmentMap();
            setDepartmentMap(null);
        } catch (error) {
            console.error(error);
        } finally {
            setIsClearingDepartments(false);
        }
    };

    const handleClearData = async () => {
        try {
            await clearSalesData();
            await clearCustomTabs();
            setOriginalData([]);
            setProcessedData(null);
            setFileInfo(null);
            setAppState('upload');
        } catch (error) {
            console.error(error);
        }
    };

    const handleSendMessage = useCallback(async (message: string) => {
        if (!processedData) return;
        setIsAiResponding(true);
        setChatHistory(prev => [...prev, { role: 'user', content: message }]);

        if (!chatSession.current) {
            chatSession.current = createChatSession(processedData);
        }

        try {
            const result = await chatSession.current.sendMessage({ message });
            setChatHistory(prev => [...prev, { role: 'model', content: result.text }]);
        } catch (error) {
            console.error("AI chat error:", error);
            setChatHistory(prev => [...prev, { role: 'model', content: "Xin lỗi, đã có lỗi xảy ra. Vui lòng thử lại." }]);
        } finally {
            setIsAiResponding(false);
        }
    }, [processedData]);

    const handleBatchExport = async (employees: Employee[]) => {
        // Implementation handled in DashboardView via ref, this is placeholder/trigger
    };

    const handleBatchKhoExport = async () => {
        // Implementation handled in DashboardView via ref, this is placeholder/trigger
    };

    return {
        status, appState, isProcessing, isClearingDepartments, isExporting, fileInfo,
        departmentMap, originalData, baseFilteredData, productConfig, processedData, employeeAnalysisData,
        configUrl, setConfigUrl, uniqueFilterOptions,
        filterState, handleFilterChange,
        activeModal, setActiveModal, modalData,
        isChatOpen, setIsChatOpen, chatHistory, isAiResponding,
        handleClearDepartments, 
        handleClearData,
        handleShiftFileProcessing,
        handleFileProcessing,
        handleSendMessage,
        openPerformanceModal: (name: string) => { setModalData({employeeName: name}); setActiveModal('performance'); },
        openUnshippedModal: () => setActiveModal('unshipped'),
        handleExport: exportElementAsImage,
        handleBatchExport,
        handleBatchKhoExport,
        isDeduplicationEnabled: true,
        handleDeduplicationChange: (enabled: boolean) => {},
        processingTime
    };
};

import * as XLSX from 'xlsx';
import { get } from 'svelte/store';
import { departmentMap, productConfig } from '../stores/dashboardStore';
import { calculateRowMetrics } from '../utils/calculationUtils';
import { summarizeKpis } from './kpiService';
import { summarizeEmployees } from './employeeService';
import type { DataRow, ProcessedData, TrendData, IndustryData } from '../types';

/**
 * Đọc và chuẩn hóa file Excel (Thay thế Worker)
 */
export async function parseExcel(file: File): Promise<DataRow[]> {
  const arrayBuffer = await file.arrayBuffer();
  // Sử dụng dense mode để tiết kiệm bộ nhớ
  const workbook = XLSX.read(new Uint8Array(arrayBuffer), { type: 'array', cellDates: true, dense: true });
  const sheetName = workbook.SheetNames[0];
  const sheet = workbook.Sheets[sheetName];
  const rawData: any[] = XLSX.utils.sheet_to_json(sheet, { defval: '' });

  const normalizeStr = (str: any) => str ? String(str).toLowerCase().trim() : '';

  return rawData.map(row => {
    // Chuẩn hóa dữ liệu cơ bản
    const normalizedKho = String(row['Mã kho tạo'] || '');
    // Logic tìm 'da' trong 'đã xuất' để xác định trạng thái
    const normalizedXuat = normalizeStr(row['Trạng thái xuất']).includes('da') ? 'Đã' : 'Chưa';
    const normalizedNguoiTao = String(row['Người tạo'] || '');
    const normalizedTrangThai = String(row['Trạng thái hồ sơ'] || '');

    // Xử lý ngày tháng
    let parsedDate = row['Ngày tạo'];
    if (!(parsedDate instanceof Date)) {
        parsedDate = new Date(parsedDate);
    }

    return {
      ...row,
      normalizedKho,
      normalizedXuat,
      normalizedNguoiTao,
      normalizedTrangThai,
      parsedDate
    };
  }).filter(r => r.parsedDate && !isNaN(r.parsedDate.getTime()));
}

/**
 * Main engine for turning raw Excel JSON into a rich data model
 */
export function processDashboardData(rows: DataRow[]): ProcessedData {
  const dailyTrends: Record<string, { revenue: number, revenueQD: number, date: Date }> = {};
  const shifts: Record<string, { revenue: number, revenueQD: number }> = {
    "Ca 1": { revenue: 0, revenueQD: 0 },
    "Ca 2": { revenue: 0, revenueQD: 0 },
    "Ca 3": { revenue: 0, revenueQD: 0 },
    "Ca 4": { revenue: 0, revenueQD: 0 },
    "Ca 5": { revenue: 0, revenueQD: 0 },
    "Ca 6": { revenue: 0, revenueQD: 0 }
  };
  const industries: Record<string, IndustryData> = {};
  const unshipped: DataRow[] = [];

  // FIX: Added explicit cast to Record<string, string> to satisfy summarizeEmployees parameter requirement
  const currentDeptMap = get(departmentMap) as Record<string, string>;

  rows.forEach(row => {
    const metrics = calculateRowMetrics(row);

    // Attach computed metrics for later use
    row.computedRevenue = metrics.revenue;
    row.computedRevenueQD = metrics.revenueQD;

    // Track unshipped orders for KPI
    if ((row['Trạng thái xuất'] || '').toString().toLowerCase().includes('chưa')) {
      unshipped.push(row);
    }

    // Process Trends
    if (row.parsedDate) {
      const dateKey = row.parsedDate.toISOString().split('T')[0];
      if (!dailyTrends[dateKey]) {
        dailyTrends[dateKey] = { revenue: 0, revenueQD: 0, date: row.parsedDate };
      }
      dailyTrends[dateKey].revenue += metrics.revenue;
      dailyTrends[dateKey].revenueQD += metrics.revenueQD;

      const hour = row.parsedDate.getHours();
      const min = row.parsedDate.getMinutes();
      let shift = "";

      if (hour === 8) shift = "Ca 1";
      else if (hour >= 9 && hour < 12) shift = "Ca 2";
      else if (hour >= 12 && hour < 15) shift = "Ca 3";
      else if (hour >= 15 && hour < 18) shift = "Ca 4";
      else if (hour >= 18 && hour < 21) shift = "Ca 5";
      else if (hour === 21 && min < 30) shift = "Ca 6";

      if (shift && shifts[shift]) {
        shifts[shift].revenue += metrics.revenue;
        shifts[shift].revenueQD += metrics.revenueQD;
      }
    }

    // Aggregate by Industry
    const indName = row['Ngành hàng'] || 'Khác';
    if (!industries[indName]) {
      industries[indName] = { name: indName, revenue: 0, quantity: 0 };
    }
    industries[indName].revenue += metrics.revenue;
    industries[indName].quantity += (parseFloat(row['Số lượng']) || 1);
  });

  return {
    kpis: summarizeKpis(rows, unshipped),
    trendData: { daily: dailyTrends, shifts },
    industryData: Object.values(industries).sort((a, b) => b.revenue - a.revenue),
    employeeData: {
      fullSellerArray: summarizeEmployees(rows, currentDeptMap),
      averages: {}
    },
    unshippedOrders: unshipped,
    lastUpdated: new Date().toLocaleString('vi-VN'),
    reportSubTitle: "Tự động phân tích theo tiêu chuẩn BI 2.0"
  };
}

